<template><view class="page"><view class="hero"><text class="eyebrow">NAMING REPORT</text><text class="title">高级命名报告</text><text class="desc">基于已保存的起名记录创建报告任务。</text></view><view v-if="context.record_id" class="creator"><text class="section-title">{{context.name||'已选候选名'}}</text><text class="hint">记录 #{{context.record_id}}<text v-if="context.candidate_id"> · 候选 #{{context.candidate_id}}</text></text><button :loading="creating" @click="create">创建报告任务</button></view><view v-else class="notice">请先在首页生成名字并点击候选卡片中的“高级报告”。</view><view class="section-head"><text>我的报告任务</text><text @click="load">刷新</text></view><view v-if="!items.length" class="empty">暂无报告任务</view><view v-for="item in items" :key="item.id" class="task"><view class="row"><text class="task-name">报告 #{{item.id}}</text><text :class="['status',item.status]">{{statusText(item.status)}}</text></view><text class="meta">记录 #{{item.record_id}} · {{formatDate(item.created_at)}}</text><text v-if="item.error_message" class="error">{{item.error_message}}</text><view class="actions"><button v-if="item.status==='completed'" size="mini" @click="detail(item)">查看报告</button><button v-if="item.status==='failed'" size="mini" @click="retry(item)">重新生成</button></view><view v-if="opened[item.id]" class="content"><text v-for="(value,key) in opened[item.id].content" :key="key"><b>{{key}}</b>：{{display(value)}}</text></view></view></view></template>
<script setup>import{ref}from'vue';import{onPullDownRefresh,onShow}from'@dcloudio/uni-app';import http from'@/http/http.js';const items=ref([]),creating=ref(false),opened=ref({}),context=ref({});const load=async()=>{const r=await http.getReportTasks({page:1,page_size:50});items.value=r.items||[];uni.stopPullDownRefresh();};onShow(()=>{context.value=uni.getStorageSync('selectedCandidate')||{};load();});onPullDownRefresh(load);const create=async()=>{creating.value=true;try{await http.createReportTask({record_id:Number(context.value.record_id),candidate_id:context.value.candidate_id?Number(context.value.candidate_id):null,report_version:'v1'});await load();uni.showToast({title:'报告任务已创建',icon:'success'});}finally{creating.value=false;}};const detail=async item=>{opened.value={...opened.value,[item.id]:await http.getReportDetail(item.id)}};const retry=async item=>{await http.retryReportTask(item.id);await load();};const statusText=v=>({pending:'排队中',processing:'生成中',completed:'已完成',failed:'失败'}[v]||v);const formatDate=v=>String(v||'').replace('T',' ').slice(0,16);const display=v=>typeof v==='object'?JSON.stringify(v):String(v);</script>
<style scoped>.page{min-height:100vh;padding:30rpx;box-sizing:border-box;background:#f7f4ee;color:#292620}.hero{padding:30rpx;color:#fff;border-radius:24rpx;background:linear-gradient(135deg,#344d41,#748b7e)}.eyebrow,.title,.desc,.hint,.meta,.error,.content text{display:block}.eyebrow{font-size:16rpx;letter-spacing:3rpx}.title{margin-top:8rpx;font-size:38rpx;font-weight:700}.desc{margin-top:9rpx;font-size:21rpx;opacity:.75}.creator,.task,.empty,.notice{margin-top:20rpx;padding:25rpx;border-radius:19rpx;background:#fff}.section-title,.task-name{font-size:27rpx;font-weight:700}.hint,.meta{margin-top:7rpx;color:#978e82;font-size:19rpx}.creator button{margin-top:18rpx;color:#fff;background:#405e50}.notice,.empty{color:#8d8377;text-align:center}.section-head,.row{display:flex;justify-content:space-between;align-items:center}.section-head{margin:35rpx 4rpx 5rpx;font-size:27rpx;font-weight:700}.section-head text:last-child{color:#557263;font-size:20rpx}.status{padding:6rpx 12rpx;border-radius:20rpx;background:#eeeae4;font-size:18rpx}.status.completed{color:#347050;background:#e5f3ea}.status.failed,.error{color:#a44e45}.actions{text-align:right}.actions button{margin:15rpx 0 0 10rpx}.content{margin-top:15rpx;padding:18rpx;border-radius:12rpx;background:#f7f5f0}.content text{margin-top:8rpx;font-size:20rpx;line-height:1.5}</style>
